import { useEffect, useState } from 'react';
import axios from 'axios';

export default function Interviews() {
  const [interviews, setInterviews] = useState([]);

  useEffect(() => {
    axios.get(process.env.REACT_APP_API_URL + '/interviews')
      .then(res => setInterviews(res.data.data || []));
  }, []);

  return (
    <div>
      <h2 className="text-2xl font-bold mb-4">Interviews</h2>
      <table className="w-full border-collapse">
        <thead>
          <tr className="bg-gray-200 text-left">
            <th className="p-2">Candidate</th>
            <th className="p-2">Interviewer</th>
            <th className="p-2">Date</th>
            <th className="p-2">Time</th>
            <th className="p-2">Type</th>
          </tr>
        </thead>
        <tbody>
          {interviews.map(interview => (
            <tr key={interview.id} className="border-b">
              <td className="p-2">{interview.candidate_name}</td>
              <td className="p-2">{interview.interviewer_name}</td>
              <td className="p-2">{interview.interview_date}</td>
              <td className="p-2">{interview.interview_time}</td>
              <td className="p-2">{interview.type}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
